import type {EKeyFilter} from "@lmb-it/kitsconcerto-types";

type KeyFilter = EKeyFilter | RegExp | undefined;

const regexForFilter = (filter: KeyFilter): RegExp | null => {
    if (!filter) return null;
    if (filter instanceof RegExp) return filter;

    switch (filter) {
        case "int":
            return /^-?\d*$/;
        case "pint":
            return /^\d*$/;
        case "num":
            // allow: -, digits, one dot
            return /^-?\d*(\.\d*)?$/;
        case "pnum":
            return /^\d*(\.\d*)?$/;
        case "money":
            // 2 decimal places max
            return /^\d*(\.\d{0,2})?$/;
        case "email":
            // permissive while typing
            return /^[^ \t\r\n@]*@?[^ \t\r\n@]*\.?[^ \t\r\n@]*$/;
        case "alpha":
            return /^[A-Za-z]*$/;
        case "alphanum":
            return /^[A-Za-z0-9]*$/;
        default:
            return null;
    }
};

// Strategy: if new value is invalid, keep previous value.
// This feels closest to Prime keyfilter behavior during typing.
export const applyKeyFilter = (
    prev: string,
    next: string,
    filter: KeyFilter,
): string => {
    const r = regexForFilter(filter);
    if (!r) return next;
    return r.test(next) ? next : prev;
};
